test_cases.python_test_script:
def test_tc_gw_batt_001_present(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs, 'GW_BatteryVoltage not detected'

def test_tc_gw_batt_002_nominal(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_battery_voltage_volts(msg.data) == 12.0

def test_tc_gw_batt_003_low(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_battery_voltage_volts(msg.data) == 9.0

def test_tc_gw_batt_004_high(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_battery_voltage_volts(msg.data) == 15.0

def test_tc_gw_batt_005_max(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_battery_voltage_volts(msg.data) == 20.0

def test_tc_gw_batt_006_periodic(can_bus):
    msgs = collect_gw_messages(can_bus, 5.0)
    assert len(msgs) >= 3

def test_tc_gw_batt_007_constant(can_bus):
    msgs = collect_gw_messages(can_bus, 3.0)
    assert msgs
    first = get_battery_voltage_volts(msgs[0].data)
    for msg in msgs:
        assert get_battery_voltage_volts(msg.data) == first

def test_tc_gw_batt_008_dlc(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert msg.dlc == GW_BATTERY_VOLTAGE_DLC
